import{_ as l,c as o,o as t,a1 as i}from"./chunks/framework.DDNAyvCW.js";const a="/assets/host_edit.BudOxAWB.png",u=JSON.parse('{"title":"编辑、克隆或删除主机","description":"","frontmatter":{},"headers":[],"relativePath":"docs/hosts/edit-clone-delete.md","filePath":"docs/hosts/edit-clone-delete.md"}'),r={name:"docs/hosts/edit-clone-delete.md"};function s(n,e,d,c,h,_){return t(),o("div",null,e[0]||(e[0]=[i('<h1 id="编辑、克隆或删除主机" tabindex="-1">编辑、克隆或删除主机 <a class="header-anchor" href="#编辑、克隆或删除主机" aria-label="Permalink to &quot;编辑、克隆或删除主机&quot;">​</a></h1><p>通过编辑配置、将主机克隆为模板或从列表中删除来管理现有主机。</p><p><img src="'+a+'" alt=""></p><h2 id="编辑主机" tabindex="-1">编辑主机 <a class="header-anchor" href="#编辑主机" aria-label="Permalink to &quot;编辑主机&quot;">​</a></h2><ol><li>在列表中右键点击主机并选择 <strong>编辑</strong>。</li><li>修改以下任意配置项： <ul><li>连接 IP 或地址</li><li>端口</li><li>用户名</li><li>认证方式（密码或 SSH 密钥）</li><li>SSH 代理设置（可选）</li><li>别名</li><li>分组</li></ul></li><li>点击 <strong>保存</strong> 应用更改。</li></ol><h2 id="克隆主机" tabindex="-1">克隆主机 <a class="header-anchor" href="#克隆主机" aria-label="Permalink to &quot;克隆主机&quot;">​</a></h2><ol><li>在列表中右键点击主机并选择 <strong>克隆</strong>。</li><li>系统打开新的主机表单，预填原主机的所有配置项。别名会自动添加 <code>_Clone</code> 后缀（例如 <code>MyServer</code> 变为 <code>MyServer_Clone</code>）。</li><li>根据需要调整各项配置。</li><li>点击 <strong>创建</strong> 添加克隆的主机。</li></ol><p>克隆会保留原主机的所有配置项，包括连接地址、端口、用户名、认证方式、SSH 代理设置、别名和分组分配。</p><h2 id="删除主机" tabindex="-1">删除主机 <a class="header-anchor" href="#删除主机" aria-label="Permalink to &quot;删除主机&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>删除主机操作不可逆。确认后，该主机的所有配置数据将被永久删除且无法恢复。</p></div><ol><li>在列表中右键点击主机并选择 <strong>删除</strong>。</li><li>出现确认对话框，请仔细核对主机名称。</li><li>确认删除以永久移除该主机。</li></ol><hr><p>参见 <a href="./index">主机管理</a> 了解所有主机操作概览。</p>',13)]))}const m=l(r,[["render",s]]);export{u as __pageData,m as default};
